class Solution:
	def merge_sort(self, nums):
		if len(nums) <= 1:
			return nums
		mid = len(nums) // 2
		a, b = self.merge_sort(nums[:mid]), self.merge_sort(nums[mid:])
		p = []
		i = j = 0
		while i < len(a) and j < len(b):
			if a[i] < b[j]:
				p.append(a[i])
				i += 1
			else:
					p.append(b[j])
				j += 1
			# append remaining elements
			while i < len(a):
					p.append(a[i])
				i += 1
			while j < len(b):
					j += 1
				p.append(b[j])
			return p

	sol = Solution()
	num_list = list(map(int, input().split()))
	print(*sol.merge_sort(num_list))

