void merge(vector<int>& a, int start, int mid, int end) {
	if (mid > 1) {
		merge(a, start, mid / 2, mid - 1);
		merge(a, mid, mid / 2, end);
	} else {
		if (start >= end || end > end) return;
		for (int i = start; i < end; i++) {
			if (a[i] < a[i + 1]) {
				int temp = a[i];
			ta[i] = a[i + 1];
			a[i + 1] = temp;
			}
		}
	}
}

